int a[N];
vector<int> g[N];
int dep[N], fat[N], son[N], siz[N];
int top[N], dfn[N], rnk[N], tim; // 链顶、节点对应时间戳、时间戳对应节点(线段树用)、时间戳
void solve(int CASE)
{
	int n, m, r, p; cin >> n >> m >> r >> p;
	fa(i, 1, n)cin >> a[i];
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	// dfs1：初始化 深度、父节点、子树大小、重儿子
	var dfs1 = [&](var dfs, int now, int fa, int d)->void {
		dep[now] = d, fat[now] = fa, siz[now] = 1, son[now] = 0;
		int max_siz = -1;
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now, d + 1);
			siz[now] += siz[to];
			if (max_siz < siz[to]) {
				max_siz = siz[to];
				son[now] = to;
			}
		}
		};

	// 构造重链剖分
	tim = 0; // 时间戳从 1 开始
	var dfs2 = [&](var dfs, int now, int t)->void {
		// t：当前链链顶
		top[now] = t, dfn[now] = ++tim, rnk[tim] = now;
		if (!son[now])return;  // 如果没有重儿子，说明是叶子

		// 1. 优先处理重儿子，链顶不变延续当前链
		dfs(dfs, son[now], t);

		// 2. 处理轻儿子，轻儿子为链顶新开一条链
		for (int to : g[now]) {
			if (to == son[now] or to == fat[now])continue;
			dfs(dfs, to, to);
		}
		};

	dfs1(dfs1, r, 0, 1);
	dfs2(dfs2, r, r);

	var t = MT::BitTree<ll>(n + 1, p);
	fa(i, 1, n)t.updateRange(i, i, a[rnk[i]]);

	// 路径修改 O(logN) * O(logN)
	var update_path = [&](int x, int y, ll k)->void {
		// 循环 O(logN) * 树状数组更新 O(logN)
		while (top[x] != top[y]) {
			// 让更深的提上来，直到 x y 在同一条链中
			if (dep[top[x]] < dep[top[y]])swap(x, y);

			// 此时对应序列区间：[ dfn[top[x]], dfn[x] ]，即 x 到 链顶 的节点们 
			t.updateRange(dfn[top[x]], dfn[x], k);
			x = fat[top[x]]; // 跳到上一条链
		}

		// 此时已在同一重链，但可能不在同一点，还存在要处理的序列区间
		if (dep[x] > dep[y])swap(x, y);

		// 此时对应序列区间：[ dfn[x], dfn[y] ]，即 x 到 y 的节点们 
		t.updateRange(dfn[x], dfn[y], k);
		};

	// 子树修改 O(logN)
	var update_subtree = [&](int x, ll k)->void {
		// 子树在 dfs 序中是连续区间 [ dfn[x], dfn[x] + siz[x] - 1 ]
		t.updateRange(dfn[x], dfn[x] + siz[x] - 1, k);
		};

	// 路径查询 O(logN) * O(logN)
	var query_path = [&](int x, int y) -> ll {
		ll res = 0;
		while (top[x] != top[y]) {
			if (dep[top[x]] < dep[top[y]]) swap(x, y);

			// 查询当前 x 到链顶的这一段区间
			res = (res + t.queryRange(dfn[top[x]], dfn[x])) % p;
			x = fat[top[x]]; // 跳到上一条链
		}

		// 处理最后在同一条链上的情况
		if (dep[x] > dep[y]) swap(x, y);
		res = (res + t.queryRange(dfn[x], dfn[y])) % p;
		return res;
		};

	// 子树查询 O(logN)
	var query_subtree = [&](int x)->ll {
		int l = dfn[x], r = dfn[x] + siz[x] - 1;
		return t.queryRange(l, r);
		};

	while (m--) {
		int op; cin >> op;
		if (op == 1) {
			int x, y, z; cin >> x >> y >> z;
			update_path(x, y, z);
		}
		else if (op == 2) {
			int x, y; cin >> x >> y;
			cout << query_path(x, y) << endl;
		}
		else if (op == 3) {
			int x, z; cin >> x >> z;
			update_subtree(x, z);
		}
		else {
			int x; cin >> x;
			cout << query_subtree(x) << endl;
		}
	}
	return;
}
